class CreateFlow(BaseFlow):
    parent = DraftParentFlow
    dax = '05A'
    entity_slot = 'title'
    goal = (
        "start a new post from scratch; initializes a post record with title, "
        "type, and empty sections"
    )
    tools = ['create_post']

    def __init__(self):
        super().__init__()
        self.slots = {
            'title': ExactSlot(priority='required'),
            'type': CategorySlot(options=['draft', 'note'], priority='required'),
            'topic': ExactSlot(priority='optional'),
        }
